"""HTML for the password-protected Brandmen remote control panel."""

import html


LOGIN_HTML = r"""<!doctype html>
<html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Brandmen — вход</title><style>
:root{color-scheme:dark;--gold:#d9a441;--bg:#0d0e10;--card:#17181b;--line:#2b2c31;--muted:#96989f}
*{box-sizing:border-box}body{margin:0;min-height:100vh;display:grid;place-items:center;background:radial-gradient(circle at 50% 10%,#2a2418 0,#111216 40%,#090a0c 100%);font:15px/1.45 Inter,"Segoe UI",sans-serif;color:#f3f3f4}
.card{width:min(420px,calc(100% - 32px));padding:38px;background:rgba(23,24,27,.94);border:1px solid var(--line);border-radius:24px;box-shadow:0 24px 80px #0009}.brand{display:flex;align-items:center;gap:12px;margin-bottom:30px}.mark{display:grid;place-items:center;width:42px;height:42px;border-radius:13px;background:var(--gold);color:#17120a;font-weight:900;font-size:20px}.brand b{font-size:20px}.brand span{display:block;color:var(--muted);font-size:12px;font-weight:500}
h1{margin:0 0 8px;font-size:25px}p{margin:0 0 24px;color:var(--muted)}label{display:block;margin:15px 0 7px;color:#c7c8cc;font-size:13px;font-weight:650}input{width:100%;padding:13px 14px;border:1px solid #34363d;border-radius:11px;background:#101114;color:#fff;font:inherit;outline:none}input:focus{border-color:var(--gold);box-shadow:0 0 0 3px #d9a44122}button{width:100%;margin-top:22px;padding:13px;border:0;border-radius:11px;background:var(--gold);color:#17120a;font:700 15px inherit;cursor:pointer}.err{padding:10px 12px;margin-bottom:16px;border:1px solid #7d3434;border-radius:10px;background:#351919;color:#ffb7b7}.foot{margin-top:22px;text-align:center;color:#6f7178;font-size:12px}
</style></head><body><main class="card"><div class="brand"><div class="mark">B</div><div><b>Brandmen</b><span>Управление экранами</span></div></div><h1>Вход в панель</h1><p>Удалённое состояние и управление планшетами.</p>__ERROR__<form method="post" action="/login"><label for="username">Логин</label><input id="username" name="username" autocomplete="username" required autofocus><label for="password">Пароль</label><input id="password" type="password" name="password" autocomplete="current-password" required><button type="submit">Войти</button></form><div class="foot">Защищённое соединение · brandmen.xykaxayc.ru</div></main></body></html>"""


PANEL_HTML = r"""<!doctype html>
<html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="csrf-token" content="__CSRF__"><title>Brandmen — управление</title><style>
:root{color-scheme:dark;--bg:#0c0d0f;--panel:#151619;--panel2:#1b1c20;--line:#2a2b30;--fg:#f3f3f4;--muted:#909299;--gold:#d9a441;--green:#56c98f;--red:#eb7070;--yellow:#e0b85d}
*{box-sizing:border-box}body{margin:0;background:linear-gradient(145deg,#17140e 0,#0d0e11 32%,#090a0c 100%) fixed;color:var(--fg);font:14px/1.45 Inter,"Segoe UI",sans-serif;min-height:100vh}button,a{font:inherit}.shell{display:grid;grid-template-columns:230px 1fr;min-height:100vh}.side{position:sticky;top:0;height:100vh;padding:24px 16px;border-right:1px solid var(--line);background:#101114eF}.brand{display:flex;align-items:center;gap:11px;padding:0 10px 28px}.mark{display:grid;place-items:center;width:38px;height:38px;border-radius:12px;background:var(--gold);color:#17120a;font-size:19px;font-weight:900}.brand b{font-size:18px}.brand small{display:block;color:var(--muted)}nav a{display:flex;gap:10px;align-items:center;padding:11px 12px;margin:4px 0;border-radius:10px;color:#b9bbc1;text-decoration:none}nav a.active{background:#d9a44118;color:#f5d89f;border:1px solid #d9a44132}.sidefoot{position:absolute;left:16px;right:16px;bottom:20px;color:var(--muted);font-size:12px}.logout{color:#bbb;text-decoration:none}.main{padding:28px 34px 60px;min-width:0}.top{display:flex;align-items:center;justify-content:space-between;gap:18px;margin-bottom:24px}.top h1{margin:0;font-size:26px}.top p{margin:4px 0 0;color:var(--muted)}.refresh{border:1px solid var(--line);background:var(--panel);color:#ddd;border-radius:10px;padding:9px 12px;cursor:pointer}.stats{display:grid;grid-template-columns:repeat(4,minmax(130px,1fr));gap:12px;margin-bottom:24px}.stat{padding:17px 18px;background:linear-gradient(145deg,#1b1c20,#141518);border:1px solid var(--line);border-radius:15px}.stat span{color:var(--muted);font-size:12px}.stat b{display:block;margin-top:4px;font-size:27px}.stat.good b{color:var(--green)}.stat.bad b{color:var(--red)}.section{margin-top:24px}.sectionhead{display:flex;align-items:center;justify-content:space-between;margin-bottom:11px}.sectionhead h2{margin:0;font-size:17px}.hint{color:var(--muted);font-size:12px}.tablewrap{overflow:auto;border:1px solid var(--line);border-radius:16px;background:var(--panel)}table{width:100%;border-collapse:collapse;min-width:840px}th,td{text-align:left;padding:14px 15px;border-bottom:1px solid #26272c;vertical-align:middle}th{color:var(--muted);font-size:11px;text-transform:uppercase;letter-spacing:.06em;background:#18191d}tr:last-child td{border-bottom:0}.device b{display:block}.device small{color:var(--muted)}.status{display:inline-flex;align-items:center;gap:7px}.dot{width:8px;height:8px;border-radius:50%;background:var(--red);box-shadow:0 0 10px currentColor}.status.on{color:var(--green)}.status.warn{color:var(--yellow)}.status.off{color:var(--red)}.status.on .dot{background:var(--green)}.status.warn .dot{background:var(--yellow)}.actions{display:flex;gap:6px;flex-wrap:wrap}.btn{border:1px solid #35363d;background:#202126;color:#ddd;border-radius:9px;padding:7px 10px;cursor:pointer}.btn:hover{border-color:#555}.btn.play{border-color:#79602d;background:#302817;color:#f4d69a}.btn.stop{border-color:#653737;background:#2d1c1c;color:#ffb3b3}.btn.danger{color:#e4a0a0}.btn:disabled{opacity:.45;cursor:wait}.empty{padding:42px;text-align:center;color:var(--muted)}.agents{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:10px}.agent{background:var(--panel);border:1px solid var(--line);border-radius:14px;padding:15px}.agent b{display:block}.agent small{color:var(--muted)}.toast{position:fixed;right:24px;bottom:24px;max-width:360px;padding:12px 16px;background:#24252a;border:1px solid #3b3c42;border-radius:11px;box-shadow:0 12px 40px #0008;display:none}.toast.err{border-color:#7b3c3c;color:#ffbcbc}
@media(max-width:850px){.shell{display:block}.side{position:relative;height:auto;border-right:0;border-bottom:1px solid var(--line);padding:14px}.brand{padding-bottom:10px}.side nav{display:flex;overflow:auto}.sidefoot{display:none}.main{padding:22px 16px 50px}.stats{grid-template-columns:repeat(2,1fr)}.top{align-items:flex-start}.top h1{font-size:22px}}
</style></head><body><div class="shell"><aside class="side"><div class="brand"><div class="mark">B</div><div><b>Brandmen</b><small>Control Center</small></div></div><nav><a class="active" href="/panel">▦ &nbsp;Экраны</a><a href="/ui">≡ &nbsp;Логи и ошибки</a></nav><div class="sidefoot">Вошли как <b>__USER__</b><br><a class="logout" href="/logout">Выйти</a></div></aside><main class="main"><div class="top"><div><h1>Экраны</h1><p>Состояние флота и безопасное удалённое управление</p></div><button class="refresh" onclick="load()">↻ Обновить</button></div><section class="stats"><div class="stat"><span>Всего планшетов</span><b id="total">—</b></div><div class="stat good"><span>Сейчас на связи</span><b id="online">—</b></div><div class="stat"><span>Требуют внимания</span><b id="warning">—</b></div><div class="stat bad"><span>Не на связи</span><b id="offline">—</b></div></section><section class="section"><div class="sectionhead"><h2>Планшеты</h2><span class="hint" id="updated">Загрузка…</span></div><div class="tablewrap"><table><thead><tr><th>Экран</th><th>Адрес</th><th>Версия</th><th>Связь</th><th>Последняя команда</th><th>Управление</th></tr></thead><tbody id="devices"></tbody></table></div></section><section class="section"><div class="sectionhead"><h2>Компьютеры на точках</h2><span class="hint">Передают список экранов и диагностику</span></div><div class="agents" id="agents"></div></section></main></div><div class="toast" id="toast"></div><script>
const csrf=document.querySelector('meta[name=csrf-token]').content,$=id=>document.getElementById(id);let busy=new Set();
const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
function ageText(m){if(m==null)return'нет данных';if(m<1)return'только что';if(m<60)return Math.round(m)+' мин назад';if(m<1440)return(m/60).toFixed(1)+' ч назад';return Math.round(m/1440)+' дн назад'}
function state(m){return m!=null&&m<2?['on','На связи']:m!=null&&m<10?['warn','Нестабильно']:['off','Не на связи']}
function lastCmd(q){if(!q||!q.length)return'—';const c=q[q.length-1],labels={launch:'Включить',stop:'Выключить',restart:'С начала',reboot:'Перезагрузить'};return '#'+c.id+' '+(labels[c.cmd]||c.cmd)+' · '+({pending:'ожидает',sent:'доставлена',done:'выполнена',error:'ошибка'}[c.status]||c.status)}
function toast(t,err=false){const e=$('toast');e.textContent=t;e.className='toast'+(err?' err':'');e.style.display='block';setTimeout(()=>e.style.display='none',4200)}
async function command(site,cmd){if(cmd==='reboot'&&!confirm('Перезагрузить этот планшет?'))return;busy.add(site);renderButtons();try{const r=await fetch('/commands/enqueue?site='+encodeURIComponent(site),{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-Token':csrf},body:JSON.stringify({cmd})});if(!r.ok)throw new Error('HTTP '+r.status);toast('Команда отправлена. Планшет получит её примерно за 15 секунд.');setTimeout(load,1800)}catch(e){toast('Не удалось отправить команду: '+e.message,true)}finally{busy.delete(site);renderButtons()}}
let cached=[];function renderButtons(){for(const d of cached){const box=document.querySelector('[data-actions="'+CSS.escape(d.site)+'"]');if(!box)continue;if(d.controllable===false){box.innerHTML='<small>Ожидает прямого подключения планшета</small>';continue}const dis=busy.has(d.site)?'disabled':'';box.innerHTML=`<button ${dis} class="btn play" onclick="command('${esc(d.site)}','launch')">▶ Включить</button><button ${dis} class="btn stop" onclick="command('${esc(d.site)}','stop')">■ Выключить</button><button ${dis} class="btn" onclick="command('${esc(d.site)}','restart')">↺ С начала</button><button ${dis} class="btn danger" onclick="command('${esc(d.site)}','reboot')">Перезагрузка</button>`}}
function render(data){cached=data.devices||[];let on=0,warn=0,off=0;for(const d of cached){const s=state(d.age_min);if(s[0]==='on')on++;else if(s[0]==='warn')warn++;else off++} $('total').textContent=cached.length;$('online').textContent=on;$('warning').textContent=warn;$('offline').textContent=off;
const tb=$('devices');tb.innerHTML=cached.length?cached.map(d=>{const s=state(d.age_min),m=d.meta||{};return `<tr><td class="device"><b>${esc(m.name||m.model||d.name||d.site)}</b><small>${esc(d.site)}</small></td><td>${esc(m.ip||d.ip||'—')}</td><td>${esc(m.v||d.version||'—')}</td><td><span class="status ${s[0]}"><i class="dot"></i>${s[1]}</span><br><small>${ageText(d.age_min)}</small></td><td><small>${esc(lastCmd(d.queue))}</small></td><td><div class="actions" data-actions="${esc(d.site)}"></div></td></tr>`}).join(''):`<tr><td colspan="6" class="empty">Планшеты ещё не выходили на связь с сервером</td></tr>`;renderButtons();
const agents=data.agents||[];$('agents').innerHTML=agents.length?agents.map(a=>`<div class="agent"><b>${esc(a.site)}</b><small>Версия ${esc(a.version||'—')} · ${ageText(a.age_min)}<br>Сохранено экранов: ${(a.devices||[]).length}</small></div>`).join(''):'<div class="agent"><b>Нет свежих данных</b><small>Windows-приложение передаст список после обновления.</small></div>'; $('updated').textContent='Обновлено '+new Date().toLocaleTimeString('ru-RU',{hour:'2-digit',minute:'2-digit',second:'2-digit'})}
async function load(){try{const r=await fetch('/api/dashboard');if(r.status===401){location='/login';return}if(!r.ok)throw new Error('HTTP '+r.status);render(await r.json())}catch(e){toast('Ошибка обновления панели: '+e.message,true)}}load();setInterval(load,10000);
</script></body></html>"""


def login_page(error=""):
    block = f'<div class="err">{html.escape(error)}</div>' if error else ""
    return LOGIN_HTML.replace("__ERROR__", block)


def panel_page(username, csrf):
    return (PANEL_HTML.replace("__USER__", html.escape(username))
            .replace("__CSRF__", html.escape(csrf)))
